import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  input,
  output,
} from '@angular/core';

/**
 * A smart component demonstrating Compodoc integration.
 */
@Component({
  selector: 'smart-ngx-smart-components',
  imports: [],
  template: `<p>NgxSmartComponents works!</p>`,
  styles: `
    :host {
      display: block;
    }
  `,
  encapsulation: ViewEncapsulation.Emulated,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NgxSmartComponents {
  /** The sample input value. */
  readonly sample = input<string>();

  /** Emitted when the sample value changes. */
  readonly sampleChange = output<string>();
}

